import scala.xml._

object XmlConfigService {
  def parseXml(xml: String): NodeSeq = {
    try {
      XML.loadString(xml)
    } catch {
      case e: Exception =>
        throw new RuntimeException("Failed to parse XML", e)
    }
  }

  def extractSettings(xml: String): Map[String, String] = {
    val root = parseXml(xml)
    (root \\ "@*").map(attr => attr.key -> attr.value).toMap
  }

  def main(args: Array[String]): Unit = {
    val xmlInput = "<config><setting key='database' value='mysql'/></config>"
    val settings = extractSettings(xmlInput)
    println(settings)
  }
}